#include <vector>
#include <unordered_map>
using namespace std;

long long solve(vector<vector<long long>> points) {
    const long long mod = 1000000007;
    const long long mod2 = mod * 2;

    unordered_map<long long, int> groups;
    for (auto& p : points) {
        long long y = p[1];
        groups[y]++;
    }

    long long S2 = 0;
    long long T2 = 0;
    for (auto it : groups) {
        int n = it.second;
        if (n < 2) continue;
        long long a = static_cast<long long>(n) * (n - 1) / 2;
        a %= mod2;
        S2 = (S2 + a) % mod2;
        T2 = (T2 + a * a) % mod2;
    }

    long long X = (S2 * S2 - T2) % mod2;
    if (X < 0) {
        X += mod2;
    }
    X %= mod2;
    long long total = X / 2;
    return total % mod;
}
```

